use warnings;
no warnings "portable";

sub mul64 {
    my ($a, $b) = @_;
    # Split into 32-bit halves, use integer arithmetic carefully
    my $a_lo = $a & 0xFFFFFFFF;
    my $a_hi = ($a >> 32) & 0xFFFFFFFF;
    my $b_lo = $b & 0xFFFFFFFF;
    my $b_hi = ($b >> 32) & 0xFFFFFFFF;

    # a*b mod 2^64 = (a_lo*b_lo) + ((a_lo*b_hi + a_hi*b_lo) << 32) mod 2^64
