    # a_lo*b_hi and a_hi*b_lo can each be up to ~4e18
    # We need to be careful about the shift

    my $ll = $a_lo * $b_lo;  # fits in u64? max 0xFFFFFFFE00000001 - yes
    my $cross = (($a_lo * $b_hi) & 0xFFFFFFFF) + (($a_hi * $b_lo) & 0xFFFFFFFF);
    # shift cross left 32 and add ll
    my $result = ($ll & 0xFFFFFFFF) | ((( ($ll >> 32) + $cross) & 0xFFFFFFFF) << 32);
